VALUES
  ('promotion-6f0ba476-moex-00255', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '下列有關適用所得稅法第4條之4房地合一課稅之房地於出售後申請適用重購退稅之規定何者有誤？', '["出售前1年須本人或其配偶、未成年子女設有戶籍並居住，且無出租、供營業或執行業務使用", "須自完成移轉登記之日起算2年內，重購自住房屋、土地", "重購之自住房屋、土地，於重購後5年內改作其他用途或再行移轉時，應追繳原扣抵或退還稅額", "重購之房地價格須高於出售之房地價格方能適用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00256', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依據現行所得稅法之規定，下列有關營利事業辦理暫繳申報之敘述何者錯誤？', '["營利事業辦理暫繳申報之期間為每年9月1日起至9月30日止", "營利事業應按其上年度結算申報營利事業所得稅應納稅額之2分之1為暫繳稅額，自行向庫繳納", "營利事業未以投資抵減稅額、行政救濟留抵稅額及扣繳稅額抵減暫繳稅額者，於自行向庫繳納 暫繳稅款後，得免辦理暫繳申報", "營利事業未依規定期間辦理暫繳申報，應處所漏稅額2倍以下之罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00257', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依所得稅法相關規定，下列何項扣除額之上限係以戶為單位？①股利可扣抵稅額  ②儲蓄投資扣除額', '["長期照護扣除額", "教育學費扣除額  ⑤房屋租金支出", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00258', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依現行稅法規定，下列何者必須計入個人之基本所得額？①綜合所得淨額230萬元  ②香港房屋', '["出售未上市未上櫃之證券交易所得60萬元", "年金保險給付30 萬元，該保險契約係於103年訂立，且受益人與要保人非屬於同一人  ⑤慈善捐贈現金100萬元", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00259', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '有關營利事業交際費之規定何者正確？①其進項稅額不得扣抵  ②簽證申報之交際費限額較藍', '["營利事業經營外銷業務，取得外匯收入者，並得在不超過當年度外銷結匯收入總額 百分之二範圍內，列支特別交際應酬費", "公營事業之交際費由主管機關分別核定，列入預算", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00260', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '外國之事業、機關、團體、組織在中華民國境內無固定營業場所，銷售電子勞務予境內自然人者， 其納稅義務人為何？', '["買受人", "該外國事業、機關、團體", "進口貨物收貨人或持有人", "銷售給自然人無須繳納營業稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00261', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '根據加值及非加值型營業稅法第 52 條規定，營業人漏開統一發票或於統一發票上短開銷售額， 於法定申報期限前經查獲者，關於課稅處罰之敘述何者錯誤？', '["因申報期限尚未屆滿，營業人可以補報免罰", "應就短漏開銷售額按規定稅率計算稅額繳納稅款，並按該稅額處5倍以下罰鍰", "處罰金額不得超過新臺幣100萬元", "一年內經查獲達3次者，並停止其營業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00262', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '甲公司為加值型營業人，銷售土地及房屋予乙公司，雙方簽訂買賣契約僅約定土地及房屋銷售總 價（含稅）為8,520萬元，未分別列示土地及房屋之售價，若該筆土地公告現值為3,000萬元，房 屋評定標準價格為1,200萬元，則房屋的銷售額為多少？', '["1,260萬元", "2,400萬元", "2,520萬元", "3,000萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00263', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '下列那一項之進項稅額可扣抵銷項稅額？', '["公司招待員工旅遊之住宿費用", "年節送禮給客戶之費用", "捐贈勞軍之支出", "購入小汽車供經理用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00264', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依據我國現行遺產及贈與稅法之規定，下列何者須計入被繼承人之遺產總額計算遺產稅？', '["被繼承人死亡時，給付其所指定受益人之人壽保險金額、軍、公教人員、勞工或農民保險之保 險金額及互助金", "被繼承人死亡前5年內，繼承之財產已納遺產稅者", "被繼承人自己創作之著作權、發明專利權及藝術品", "遺產中作農業使用之農業用地及其地上農作物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL)
